/**
 * Regenerate all favicon assets from the high-res source (BS 500x500.png).
 * Run: node scripts/generate-favicons.js
 *
 * Why: Apple Touch Icon is 180x180. If it was generated by upscaling 32x32,
 * it looks blurry on iPhone/iPad. This script downscales from 500x500 so
 * every size is crisp.
 */

const fs = require('fs');
const path = require('path');

const LOGOS_DIR = path.join(__dirname, '..', 'logos');
const SOURCE = path.join(LOGOS_DIR, 'BS 500x500.png');

const SIZES = [
  { name: 'favicon-16x16.png', size: 16 },
  { name: 'favicon-32x32.png', size: 32 },
  { name: 'apple-touch-icon.png', size: 180 },
  { name: 'android-chrome-192x192.png', size: 192 },
  { name: 'android-chrome-512x512.png', size: 512 },
];

async function main() {
  if (!fs.existsSync(SOURCE)) {
    console.error('Source not found:', SOURCE);
    process.exit(1);
  }

  const sharp = require('sharp');
  const pngToIco = (await import('png-to-ico')).default;

  const buffer = await sharp(SOURCE)
    .resize(500, 500)
    .png()
    .toBuffer();

  for (const { name, size } of SIZES) {
    const outPath = path.join(LOGOS_DIR, name);
    await sharp(buffer)
      .resize(size, size)
      .png()
      .toFile(outPath);
    console.log('Wrote', name);
  }

  // Build favicon.ico from 16 and 32 (multi-size ICO = crisp at any display size)
  const favicon16 = path.join(LOGOS_DIR, 'favicon-16x16.png');
  const favicon32 = path.join(LOGOS_DIR, 'favicon-32x32.png');
  const icoBuf = await pngToIco([favicon16, favicon32]);
  fs.writeFileSync(path.join(LOGOS_DIR, 'favicon.ico'), icoBuf);
  console.log('Wrote favicon.ico (16+32)');
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
